package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases adds a few *new* edge‑case scenarios for
// Order.CalculateTotal().  The existing suite already covers:
//   - empty slice, nil slice, single item, many items, float‑precision,
//     overwriting a previous total, etc.
// The cases below are **not** duplicated there:
//
//   1. Very large price × quantity (overflow → +Inf)
//   2. Zero price with a huge quantity (total stays 0)
//   3. NaN price (total becomes NaN)
//   4. Mixed Inf/NaN values (the first NaN dominates the sum)
//
// Each sub‑test creates an Order, populates its Items slice directly (bypassing
// validation), calls CalculateTotal() and checks the resulting `Total` field.
//
// The test is table‑driven and uses t.Run() so the output is easy to read and
// integrates nicely with the project's existing test pattern.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	type testCase struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantIsNaN   bool
		wantIsInf   bool
		description string
	}

	const hugeQty = 1_000_000_000 // 1 billion – large enough to trigger overflow
	const hugePrice = 1e308       // close to MaxFloat64 (≈1.79e308)

	cases := []testCase{
		{
			name: "LargePriceAndQuantity_OverflowToInf",
			items: []OrderItem{
				{ProductID: 1, Quantity: hugeQty, Price: hugePrice},
			},
			// 1e308 * 1e9 = 1e317 → +Inf (float64 overflow)
			wantTotal: math.Inf(1),
			wantIsInf: true,
			description: "price and quantity are both huge, sum overflows to +Inf",
		},
		{
			name: "ZeroPriceLargeQuantity_ZeroTotal",
			items: []OrderItem{
				{ProductID: 2, Quantity: hugeQty, Price: 0},
			},
			wantTotal: 0,
			description: "price is zero, even a huge quantity must keep total at 0",
		},
		{
			name: "NaNPrice_ProducesNaNTotal",
			items: []OrderItem{
				{ProductID: 3, Quantity: 5, Price: math.NaN()},
			},
			wantIsNaN: true,
			description: "any NaN price should propagate to the total",
		},
		{
			name: "MixedInfAndNaN_NaNDominates",
			items: []OrderItem{
				{ProductID: 4, Quantity: 1, Price: math.Inf(1)},
				{ProductID: 5, Quantity: 2, Price: math.NaN()},
			},
			wantIsNaN: true,
			description: "NaN in the sum should make the final total NaN even if Inf is present",
		},
		{
			name: "NegativeQuantity_ButCalculateTotalIgnoresValidation",
			// Validation would reject a negative quantity, but CalculateTotal
			// simply multiplies Quantity*Price, so we can still test the arithmetic.
			items: []OrderItem{
				{ProductID: 6, Quantity: -3, Price: 100},
			},
			wantTotal: -300,
			description: "negative quantity is allowed here (validation is separate) and should affect the total",
		},
	}

	for _, tc := range cases {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			// Arrange
			o := &Order{
				Items: tc.items,
			}

			// Act
			o.CalculateTotal()

			// Assert – check the stored Total field
			if tc.wantIsNaN {
				if !math.IsNaN(o.Total) {
					t.Fatalf("expected Total to be NaN, got %v", o.Total)
				}
				return
			}
			if tc.wantIsInf {
				if !math.IsInf(o.Total, 1) {
					t.Fatalf("expected Total to be +Inf, got %v", o.Total)
				}
				return
			}
			if o.Total != tc.wantTotal {
				t.Fatalf("unexpected Total: want %v, got %v", tc.wantTotal, o.Total)
			}
		})
	}
}
```

### Why this test does **not** duplicate existing ones
| Existing test | What it covers | What this test adds |
|---------------|----------------|---------------------|
| `TestUnitOrderCalculateTotal` / `TestUnitOrderCalculateTotalLargeOrder` | Normal ranges, up to 10 items, typical prices | Extreme numeric values (overflow → Inf) |
| `TestUnitOrderCalculateTotalFloatPrecision` | Small floating‑point rounding errors | NaN propagation and negative quantity arithmetic |
| `TestUnitOrderCalculateTotalNilItems` / `TestUnitOrderCalculateTotalMixedPrices` | Nil slice, mixed normal prices | Zero‑price huge‑quantity case, mixed Inf/NaN behavior |
| `TestUnitOrderCalculateTotalOverwritesPrevious` | Idempotence of repeated calls | No new behavior – omitted here |

Thus the new test explores numeric edge‑cases (overflow, zero‑price, NaN, Inf, negative quantity) that are not exercised elsewhere in the suite.

