// TestUnitOrderCalculateTotalEdgeCases – новые edge‑case‑тесты для Order.CalculateTotal.
// Они не пересекаются с уже существующими тестами
// (TestUnitOrderCalculateTotal*, TestUnitOrderCalculateTotalVariousItemCounts, …)
// и проверяют «крайние» варианты входных данных.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	const eps = 1e-9 // допуск для сравнения float64

	tests := []struct {
		name      string
		items     []OrderItem
		wantTotal float64
	}{
		{
			name: "ZeroQuantity",
			// Quantity == 0 (некорректно с точки зрения валидации,
			// но CalculateTotal не проверяет её – просто игнорирует)
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 123.45},
				{ProductID: 2, Quantity: 5, Price: 10.0},
			},
			// 0*123.45 + 5*10 = 50
			wantTotal: 50.0,
		},
		{
			name: "ZeroPrice",
			// Цена == 0 (допустимо, например, бесплатный товар)
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, Price: 0.0},
				{ProductID: 2, Quantity: 2, Price: 25.0},
			},
			// 3*0 + 2*25 = 50
			wantTotal: 50.0,
		},
		{
			name: "ZeroQuantityAndPrice",
			// Оба поля нулевые – итог должен быть 0
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 0.0},
				{ProductID: 2, Quantity: 0, Price: 99.99},
			},
			wantTotal: 0.0,
		},
		{
			name: "LargeQuantityAndPrice_OverflowToInf",
			// Очень большие числа, которые приводят к переполнению float64.
			// Ожидаем +Inf, а не panic.
			items: []OrderItem{
				{
					ProductID: 1,
					Quantity:  int(math.MaxInt64), // 9 223 372 036 854 775 807
					Price:     1e308,               // почти максимальное значение float64
				},
			},
			wantTotal: math.Inf(1),
		},
		{
			name: "NegativePriceAndQuantity",
			// Негативные значения не проверяются в CalculateTotal,
			// поэтому они просто участвуют в сумме (получаем отрицательный total).
			items: []OrderItem{
				{ProductID: 1, Quantity: -2, Price: 50.0},
				{ProductID: 2, Quantity: 3, Price: -30.0},
			},
			// (-2)*50 + 3*(-30) = -100 - 90 = -190
			wantTotal: -190.0,
		},
		{
			name: "VerySmallPriceAndLargeQuantity",
			// Тестируем точность при большом количестве мелких сумм.
			items: []OrderItem{
				{ProductID: 1, Quantity: 1_000_000, Price: 0.000001},
				{ProductID: 2, Quantity: 2_000_000, Price: 0.000002},
			},
			// 1 000 000*0.000001 = 1.0
			// 2 000 000*0.000002 = 4.0
			// total = 5.0
			wantTotal: 5.0,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			o := &Order{
				Items: tt.items,
			}
			o.CalculateTotal()

			if math.IsInf(tt.wantTotal, 1) {
				if !math.IsInf(o.Total, 1) {
					t.Fatalf("expected Total = +Inf, got %v", o.Total)
				}
				return
			}

			if diff := math.Abs(o.Total - tt.wantTotal); diff > eps {
				t.Fatalf("total mismatch: want %v, got %v (diff %v)", tt.wantTotal, o.Total, diff)
			}
		})
	}
}
