    p1 := entity.Product{CategoryID: 1, Name: "Латте", Price: 350}
    p2 := entity.Product{CategoryID: 1, Name: "Espresso", Price: 300}
    // … repo.Create(p1), repo.Create(p2) …

    // 2️⃣  Выполняем поиск:
    results, err := repo.Search("латте", 20)

    // 3️⃣  Ожидаем, что в results будет ровно один элемент – p1.
    if err != nil { t.Fatalf("unexpected error: %v", err) }
