func TestAPIOrderFullFlow(t *testing.T) {
	// --------------------------------------------------------------------
	// 1️⃣  Build a fresh in‑memory server (all repos, use‑cases and handlers)
	// --------------------------------------------------------------------
	srv := setupTestServer(t) // returns *httptest.Server, registers cleanup
	defer srv.Close()

	// --------------------------------------------------------------------
	// 2️⃣  Create a category – the API expects JSON:
	//     { "name": "Кофе", "slug": "coffee", "description": "All coffee", "sort_order": 1 }
	// --------------------------------------------------------------------
	catPayload := `{
		"name": "Кофе",
		"slug": "coffee",
		"description": "All coffee",
		"sort_order": 1
	}`
	catResp := postJSON(t, srv.URL+"/categories", catPayload)
	require.Equal(t, http.StatusCreated, catResp.Code)

	var cat struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, catResp.Body, &cat)

	// --------------------------------------------------------------------
	// 3️⃣  Create a product that belongs to the category we just created.
	//     The product payload must contain a valid CategoryID.
	// --------------------------------------------------------------------
	prodPayload := `{
		"name": "Латте",
		"category_id": %d,
		"price": 350,
		"description": "Smooth latte",
		"image_url": "https://example.com/latte.png",
		"in_stock": true
	}`
	prodResp := postJSON(t, srv.URL+"/products", 
	                     fmt.Sprintf(prodPayload, cat.ID))
	require.Equal(t, http.StatusCreated, prodResp.Code)

	var prod struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, prodResp.Body, &prod)

	// --------------------------------------------------------------------
	// 4️⃣  Create an order that references the product.
	//     The order payload follows the shape used by the other order tests:
	// --------------------------------------------------------------------
	orderPayload := `{
		"customer_id": "alice@example.com",
		"items": [
			{ "product_id": %d, "quantity": 3 }
		]
	}`
	orderResp := postJSON(t, srv.URL+"/orders", 
	                      fmt.Sprintf(orderPayload, prod.ID))
	require.Equal(t, http.StatusCreated, orderResp.Code)

	var order struct {
		ID        int64   `json:"id"`
		Total     float64 `json:"total"`
		Status    string  `json:"status"`
		CreatedAt string  `json:"created_at"`
	}
	decodeBody(t, orderResp.Body, &order)

	// The use‑case sets the status to “new” and calculates the total.
	require.Equal(t, "new", order.Status)
	require.InDelta(t, 350*3, order.Total, 0.01)

