	// 5️⃣  Process the order (new → processing)
	// --------------------------------------------------------------------
	processResp := putJSON(t, srv.URL+"/orders/"+fmt.Sprint(order.ID)+"/process", "")
	require.Equal(t, http.StatusOK, processResp.Code)

